import type { Metadata } from "next";
import EquipmentOee from "./EquipmentOee";

export const metadata: Metadata = {
  title: "設備保全・OEE ダッシュボード | ぐんじょう",
  description:
    "製造ラインの保全課・管理者向けダッシュボード。総合設備効率(OEE)を可用率×性能×品質の3要素に分解し各目標との対比を表示。設備一覧（稼働中/停止/故障/保全中）、稼働状態・当日OEE・MTBF/MTTR・前回/次回保全日、停止要因のパレート集計（累積%・80%基準線）、予防保全スケジュールを備えたショップフロア向け画面。",
};

export default function EquipmentOeePage() {
  return <EquipmentOee />;
}

"use client"

import * as React from "react"
import type { ColumnDef } from "@tanstack/react-table"
import {
  IconRefresh,
  IconDownload,
  IconCircleCheckFilled,
  IconAlertTriangleFilled,
  IconCalendarPlus,
  IconClockHour4,
  IconArrowDownRight,
  IconArrowUpRight,
} from "@tabler/icons-react"
import {
  Container,
  VStack,
  HStack,
  Cluster,
  Grid,
  Card,
  CardHeader,
  CardTitle,
  CardDescription,
  CardContent,
  Statistic,
  Meter,
  Delta,
  Badge,
  Button,
  Select,
  Separator,
  Alert,
  AlertTitle,
  AlertDescription,
  Icon,
  DataTable,
  Timeline,
  TimelineItem,
  TimelineTitle,
  TimelineDescription,
  TimelineTime,
} from "@gunjo/ui"

import {
  oeeFactors,
  equipment,
  downtimeCausesRaw,
  summaryMetrics,
  maintenancePlans,
  type Equipment,
  type OeeFactor,
  type SummaryMetric,
  type MaintenanceKind,
} from "./data"
import { STATUS_CONFIG, StatusBadge } from "./status"
import { ParetoChart } from "./ParetoChart"

const dateFmt = new Intl.DateTimeFormat("ja-JP", { month: "short", day: "numeric" })
const weekdayFmt = new Intl.DateTimeFormat("ja-JP", { weekday: "short" })
const fmtDate = (iso: string) => dateFmt.format(new Date(iso))

const MAINT_KIND_LABEL: Record<MaintenanceKind, string> = {
  preventive: "予防保全",
  inspection: "点検",
  overhaul: "オーバーホール",
  corrective: "事後保全",
}

/** OEE要素カード: Meter の direction="higher-is-better" + target で目標との対比を表現。 */
function OeeFactorCard({ factor, primary }: { factor: OeeFactor; primary?: boolean }) {
  const delta = factor.value - factor.prevValue
  const met = factor.value >= factor.target
  return (
    <Card className={primary ? "border-primary/40" : undefined}>
      <CardHeader className="gap-2 p-5 pb-3">
        <Cluster justify="between" align="start" className="w-full">
          <CardTitle as="h3" className={primary ? "text-base" : "text-sm"}>
            {factor.label}
          </CardTitle>
          {/* 達成/未達を色だけに頼らず、アイコン＋文言で示す */}
          <Badge variant={met ? "success" : "warning"} className="gap-1 shrink-0">
            <Icon
              icon={met ? IconCircleCheckFilled : IconAlertTriangleFilled}
              size="xs"
            />
            {met ? "目標達成" : "目標未達"}
          </Badge>
        </Cluster>
      </CardHeader>
      <CardContent className="px-5 pb-5">
        <div className="flex items-baseline gap-2">
          <span
            className={
              "font-bold tabular-nums tracking-tight " +
              (primary ? "text-4xl" : "text-3xl")
            }
          >
            {factor.value.toFixed(1)}
            <span className="text-lg font-semibold text-muted-foreground">%</span>
          </span>
          <Delta
            value={Number(delta.toFixed(1))}
            format={(v) => `${v > 0 ? "+" : ""}${v.toFixed(1)}pt`}
            labels={{ positive: "改善", negative: "悪化", zero: "横ばい" }}
          />
          <span className="text-xs text-muted-foreground">前日比</span>
        </div>

        <Meter
          className="mt-3"
          label={`目標 ${factor.target}%`}
          direction="higher-is-better"
          value={factor.value}
          target={factor.target}
          max={100}
          unit="%"
        />

        <p className="mt-3 text-xs leading-relaxed text-muted-foreground">
          {factor.description}
        </p>
      </CardContent>
    </Card>
  )
}

/** サマリ指標: 「下がるほど良い」指標は delta の tone を反転して正しく良/悪を表現。 */
function SummaryStat({ metric }: { metric: SummaryMetric }) {
  const lowerBetter = metric.betterWhen === "lower"
  const improved = lowerBetter ? metric.delta < 0 : metric.delta > 0
  const trend: "up" | "down" | "flat" =
    metric.delta === 0 ? "flat" : metric.delta > 0 ? "up" : "down"
  const tone: "positive" | "negative" | "neutral" =
    metric.delta === 0 ? "neutral" : improved ? "positive" : "negative"
  const sign = metric.delta > 0 ? "+" : ""
  return (
    <Statistic
      label={metric.label}
      value={metric.value}
      trend={trend}
      tone={tone}
      change={`${sign}${metric.delta} ${metric.deltaUnit}`}
      hint={`${metric.hint}・${improved ? "改善" : metric.delta === 0 ? "横ばい" : "悪化"}`}
    />
  )
}

export default function EquipmentOee() {
  const [line, setLine] = React.useState<string>("all")

  const lines = React.useMemo(
    () => ["all", ...Array.from(new Set(equipment.map((e) => e.line)))],
    []
  )
  const rows = React.useMemo(
    () => (line === "all" ? equipment : equipment.filter((e) => e.line === line)),
    [line]
  )

  const faultCount = equipment.filter((e) => e.status === "fault").length

  const columns = React.useMemo<ColumnDef<Equipment>[]>(
    () => [
      {
        accessorKey: "id",
        header: "設備番号",
        cell: ({ row }) => (
          <span className="font-mono text-xs font-medium">{row.original.id}</span>
        ),
      },
      {
        accessorKey: "name",
        header: "設備名 / ライン",
        cell: ({ row }) => (
          <div className="min-w-0">
            <div className="font-medium">{row.original.name}</div>
            <div className="text-xs text-muted-foreground">{row.original.line}</div>
          </div>
        ),
      },
      {
        accessorKey: "status",
        header: "稼働状態",
        cell: ({ row }) => <StatusBadge status={row.original.status} />,
        sortingFn: (a, b) =>
          STATUS_CONFIG[a.original.status].label.localeCompare(
            STATUS_CONFIG[b.original.status].label,
            "ja"
          ),
      },
      {
        accessorKey: "oee",
        header: "当日OEE / 稼働率",
        cell: ({ row }) => {
          const e = row.original
          if (e.status === "stopped" || e.status === "maintenance") {
            return <span className="text-xs text-muted-foreground">—（停止中）</span>
          }
          return (
            <div className="w-36 max-w-full">
              <Meter
                size="inline"
                direction="higher-is-better"
                value={e.oee}
                target={85}
                max={100}
                label={`OEE ${e.oee}%`}
              />
              <div className="mt-0.5 text-[11px] text-muted-foreground tabular-nums">
                稼働率 {e.utilization.toFixed(1)}%
              </div>
            </div>
          )
        },
      },
      {
        id: "mtbfmttr",
        header: "MTBF / MTTR",
        cell: ({ row }) => (
          <div className="text-xs tabular-nums">
            <div>MTBF {row.original.mtbf} h</div>
            <div className="text-muted-foreground">MTTR {row.original.mttr} min</div>
          </div>
        ),
      },
      {
        accessorKey: "lastMaintenance",
        header: "前回 / 次回保全",
        cell: ({ row }) => {
          const next = new Date(row.original.nextMaintenance)
          const overdue = next.getTime() < new Date("2026-06-24").getTime()
          return (
            <div className="text-xs tabular-nums">
              <div className="text-muted-foreground">
                前回 {fmtDate(row.original.lastMaintenance)}
              </div>
              <div className={overdue ? "font-semibold text-destructive" : undefined}>
                次回 {fmtDate(row.original.nextMaintenance)}
                {overdue ? "（期限超過）" : ""}
              </div>
            </div>
          )
        },
      },
    ],
    []
  )

  return (
    <Container size="xl" className="py-6 sm:py-8">
      <VStack gap={6} align="stretch">
        {/* ヘッダー */}
        <header>
          <Cluster justify="between" align="start" className="w-full gap-4">
            <div className="min-w-0">
              <p className="text-xs font-medium text-muted-foreground">
                製造ライン管理 / 保全課
              </p>
              <h1 className="mt-0.5 text-2xl font-bold tracking-tight sm:text-3xl">
                設備保全・OEE ダッシュボード
              </h1>
              <p className="mt-1 text-sm text-muted-foreground">
                第1工場 ラインA ・ 2026年6月24日（水）15:10 時点
              </p>
            </div>
            <Cluster gap={2} className="shrink-0">
              <Button variant="outline" size="sm">
                <Icon icon={IconRefresh} size="sm" />
                <span className="hidden sm:inline">更新</span>
              </Button>
              <Button variant="default" size="sm">
                <Icon icon={IconDownload} size="sm" />
                <span className="hidden sm:inline">日報出力</span>
              </Button>
            </Cluster>
          </Cluster>
        </header>

        {/* 異常アラート（故障あり時） */}
        {faultCount > 0 && (
          <Alert variant="destructive">
            <IconAlertTriangleFilled />
            <AlertTitle as="h2">
              設備故障 {faultCount} 件 — 保全課の対応が必要です
            </AlertTitle>
            <AlertDescription>
              400tプレス機 #2（PR-02）が金型クランプ油圧低下で停止中。MTTR が
              目標を超過しています。対応状況は設備一覧で確認してください。
            </AlertDescription>
          </Alert>
        )}

        {/* OEE 内訳 */}
        <section aria-labelledby="oee-heading">
          <h2 id="oee-heading" className="mb-3 text-lg font-semibold">
            OEE 内訳（可用率 × 性能 × 品質）
          </h2>
          <Grid cols={1} gap={4} className="lg:grid-cols-4">
            {oeeFactors.map((f) => (
              <OeeFactorCard key={f.key} factor={f} primary={f.key === "oee"} />
            ))}
          </Grid>
        </section>

        {/* サマリ指標 */}
        <section aria-labelledby="summary-heading">
          <h2 id="summary-heading" className="mb-3 text-lg font-semibold">
            保全KPI（前週/前月比）
          </h2>
          <Grid cols={1} gap={4} className="sm:grid-cols-2 lg:grid-cols-4">
            {summaryMetrics.map((m) => (
              <SummaryStat key={m.key} metric={m} />
            ))}
          </Grid>
        </section>

        {/* 設備一覧 */}
        <section aria-labelledby="equipment-heading">
          <Cluster justify="between" align="end" className="mb-3 w-full gap-3">
            <h2 id="equipment-heading" className="text-lg font-semibold">
              設備一覧
            </h2>
            <div className="w-44">
              <Select
                label="ライン絞り込み"
                value={line}
                onChange={(e) => setLine(e.target.value)}
              >
                {lines.map((l) => (
                  <option key={l} value={l}>
                    {l === "all" ? "全ライン" : l}
                  </option>
                ))}
              </Select>
            </div>
          </Cluster>

          <DataTable
            columns={columns}
            data={rows}
            filter={{ columnId: "name", placeholder: "設備名で検索…" }}
            pageSize={10}
            renderCard={(e) => (
              <Card className="p-4">
                <Cluster justify="between" align="start" className="w-full">
                  <div className="min-w-0">
                    <div className="font-mono text-xs text-muted-foreground">
                      {e.id}
                    </div>
                    <div className="font-medium">{e.name}</div>
                    <div className="text-xs text-muted-foreground">{e.line}</div>
                  </div>
                  <StatusBadge status={e.status} />
                </Cluster>
                {e.status !== "stopped" && e.status !== "maintenance" && (
                  <Meter
                    className="mt-3"
                    direction="higher-is-better"
                    value={e.oee}
                    target={85}
                    max={100}
                    unit="%"
                    label="当日OEE（目標85%）"
                  />
                )}
                <HStack
                  justify="between"
                  className="mt-3 text-xs tabular-nums text-muted-foreground"
                >
                  <span>MTBF {e.mtbf}h / MTTR {e.mttr}min</span>
                  <span>次回保全 {fmtDate(e.nextMaintenance)}</span>
                </HStack>
                {e.note && (
                  <p className="mt-2 text-xs text-muted-foreground">{e.note}</p>
                )}
              </Card>
            )}
          />
        </section>

        {/* 停止要因パレート + 予防保全スケジュール */}
        <Grid cols={1} gap={6} className="lg:grid-cols-2">
          <section aria-labelledby="pareto-heading">
            <Card>
              <CardHeader>
                <CardTitle as="h2" className="text-lg" id="pareto-heading">
                  停止要因の集計（パレート）
                </CardTitle>
                <CardDescription>
                  当月累計の停止時間。累積80%に達するまでの要因が重点改善対象。
                </CardDescription>
              </CardHeader>
              <CardContent>
                <ParetoChart causes={downtimeCausesRaw} />
              </CardContent>
            </Card>
          </section>

          <section aria-labelledby="schedule-heading">
            <Card>
              <CardHeader>
                <Cluster justify="between" align="start" className="w-full">
                  <div>
                    <CardTitle as="h2" className="text-lg" id="schedule-heading">
                      予防保全スケジュール
                    </CardTitle>
                    <CardDescription>直近の保全計画（予定）</CardDescription>
                  </div>
                  <Button variant="outline" size="sm">
                    <Icon icon={IconCalendarPlus} size="sm" />
                    予定追加
                  </Button>
                </Cluster>
              </CardHeader>
              <CardContent>
                <Timeline>
                  {maintenancePlans.map((p, i) => {
                    const d = new Date(p.date)
                    const isLast = i === maintenancePlans.length - 1
                    return (
                      <TimelineItem
                        key={`${p.equipmentId}-${p.date}-${i}`}
                        connector={!isLast}
                        variant={p.overdue ? "destructive" : "info"}
                        marker={
                          <Icon
                            icon={p.overdue ? IconAlertTriangleFilled : IconClockHour4}
                            size="sm"
                            className={
                              p.overdue ? "text-destructive" : "text-info"
                            }
                          />
                        }
                      >
                        <TimelineTime dateTime={p.date}>
                          {fmtDate(p.date)}（{weekdayFmt.format(d)}）
                        </TimelineTime>
                        <TimelineTitle>
                          {p.title}
                          {p.overdue && (
                            <Badge
                              variant="destructive"
                              className="ml-2 align-middle"
                            >
                              期限超過
                            </Badge>
                          )}
                        </TimelineTitle>
                        <TimelineDescription>
                          {p.equipmentName}（{p.equipmentId}）
                        </TimelineDescription>
                        <TimelineDescription as="div" className="mt-1">
                          <Cluster gap={2}>
                            <Badge variant="secondary">
                              {MAINT_KIND_LABEL[p.kind]}
                            </Badge>
                            <span className="text-xs text-muted-foreground">
                              {p.assignee}・{p.durationLabel}
                            </span>
                          </Cluster>
                        </TimelineDescription>
                      </TimelineItem>
                    )
                  })}
                </Timeline>
              </CardContent>
            </Card>
          </section>
        </Grid>

        <Separator />
        <p className="text-center text-xs text-muted-foreground">
          データは設備IoTゲートウェイより5分間隔で自動収集。OEE = 可用率 × 性能 × 品質。
        </p>
      </VStack>
    </Container>
  )
}

"use client"

import * as React from "react"
import { Separator } from "@gunjo/ui"
import type { DowntimeCause } from "./data"

interface ParetoRow extends DowntimeCause {
  pct: number // この要因の構成比 (%)
  cumPct: number // 累積構成比 (%)
}

function buildPareto(causes: DowntimeCause[]): { rows: ParetoRow[]; total: number } {
  const sorted = [...causes].sort((a, b) => b.minutes - a.minutes)
  const total = sorted.reduce((s, c) => s + c.minutes, 0) || 1
  let cum = 0
  const rows = sorted.map((c) => {
    const pct = (c.minutes / total) * 100
    cum += pct
    return { ...c, pct, cumPct: cum }
  })
  return { rows, total }
}

/**
 * 停止要因パレート図。
 *
 * @gunjo/ui には Pareto / bar+line コンボチャートが無いため、HTML/CSS で自作。
 * BarChart は averageValue で1本の参照線しか引けず、降順ソート前提の累積%折れ線も
 * 持たないため要件を満たせなかった。CLAUDE.md のチャート方針（データ駆動チャートは
 * SVG ではなく HTML/CSS レイアウトで）に従い、棒・累積点・80%基準線を div で描画する。
 */
export function ParetoChart({ causes }: { causes: DowntimeCause[] }) {
  const { rows, total } = buildPareto(causes)
  const maxMin = Math.max(...rows.map((r) => r.minutes), 1)

  return (
    <div>
      {/* グラフ本体: 棒（左軸=分） + 累積%の点・折れ線（右軸=%, 0-100） */}
      <div
        className="relative flex h-56 items-end gap-2 sm:gap-3"
        role="img"
        aria-label={`停止要因パレート図。総停止時間 ${total} 分。上位要因順に表示。`}
      >
        {/* 80% 基準線（右軸） */}
        <div
          aria-hidden
          className="pointer-events-none absolute inset-x-0 border-t-2 border-dashed border-foreground/70"
          style={{ bottom: "80%" }}
        >
          <span className="absolute -top-5 right-0 rounded bg-foreground px-1.5 py-0.5 text-[10px] font-semibold text-background">
            累積 80% ライン
          </span>
        </div>

        {/* 累積%折れ線（点を結ぶ） */}
        <svg
          aria-hidden
          className="pointer-events-none absolute inset-0 h-full w-full overflow-visible"
          preserveAspectRatio="none"
        >
          <polyline
            points={rows
              .map((r, i) => {
                const x = ((i + 0.5) / rows.length) * 100
                const y = 100 - r.cumPct
                return `${x}%,${y}%`
              })
              .join(" ")}
            fill="none"
            stroke="hsl(var(--primary))"
            strokeWidth={2}
            vectorEffect="non-scaling-stroke"
          />
        </svg>

        {rows.map((r, i) => {
          const barH = (r.minutes / maxMin) * 100
          const overEighty = r.cumPct <= 80
          return (
            <div
              key={r.cause}
              className="relative flex h-full min-w-0 flex-1 flex-col items-center justify-end"
            >
              {/* 累積%の点 */}
              <span
                aria-hidden
                className="absolute z-10 h-2.5 w-2.5 -translate-y-1/2 rounded-full border-2 border-background bg-primary"
                style={{ bottom: `${r.cumPct}%` }}
                title={`累積 ${r.cumPct.toFixed(0)}%`}
              />
              {/* 棒 */}
              <div
                className={
                  "w-full max-w-12 rounded-t " +
                  (overEighty ? "bg-warning" : "bg-secondary")
                }
                style={{ height: `${barH}%` }}
                title={`${r.cause}: ${r.minutes}分 (${r.pct.toFixed(0)}%)`}
              />
            </div>
          )
        })}
      </div>

      {/* X軸ラベル */}
      <div className="mt-2 flex gap-2 sm:gap-3">
        {rows.map((r) => (
          <div
            key={r.cause}
            className="min-w-0 flex-1 text-center text-[11px] leading-tight text-muted-foreground"
          >
            {r.cause}
          </div>
        ))}
      </div>

      <Separator className="my-4" />

      {/* アクセシブルなデータ表（折れ線/棒の数値ソース） */}
      <table className="w-full text-sm">
        <caption className="sr-only">
          停止要因別の停止時間・構成比・累積構成比
        </caption>
        <thead>
          <tr className="text-left text-xs text-muted-foreground">
            <th scope="col" className="py-1 font-medium">
              停止要因
            </th>
            <th scope="col" className="py-1 text-right font-medium">
              停止時間
            </th>
            <th scope="col" className="py-1 text-right font-medium">
              構成比
            </th>
            <th scope="col" className="py-1 text-right font-medium">
              累積%
            </th>
          </tr>
        </thead>
        <tbody>
          {rows.map((r) => (
            <tr key={r.cause} className="border-t border-border">
              <th scope="row" className="py-1.5 text-left font-normal">
                {r.cumPct <= 80 ? (
                  <span className="font-semibold">
                    {r.cause}
                    <span className="ml-1 rounded bg-warning-subtle px-1 text-[10px] font-semibold text-warning-subtle-foreground">
                      重点
                    </span>
                  </span>
                ) : (
                  r.cause
                )}
              </th>
              <td className="py-1.5 text-right tabular-nums">{r.minutes} 分</td>
              <td className="py-1.5 text-right tabular-nums text-muted-foreground">
                {r.pct.toFixed(1)}%
              </td>
              <td className="py-1.5 text-right tabular-nums font-medium">
                {r.cumPct.toFixed(0)}%
              </td>
            </tr>
          ))}
        </tbody>
        <tfoot>
          <tr className="border-t border-border font-medium">
            <th scope="row" className="py-1.5 text-left">
              合計
            </th>
            <td className="py-1.5 text-right tabular-nums">{total} 分</td>
            <td className="py-1.5 text-right tabular-nums text-muted-foreground">
              100%
            </td>
            <td className="py-1.5 text-right" />
          </tr>
        </tfoot>
      </table>
    </div>
  )
}

"use client"

import * as React from "react"
import {
  IconPlayerPlayFilled,
  IconPlayerStopFilled,
  IconAlertTriangleFilled,
  IconTool,
  type IconProps,
} from "@tabler/icons-react"
import { Badge, Icon } from "@gunjo/ui"
import type { EquipmentStatus } from "./data"

type Glyph = React.ForwardRefExoticComponent<
  IconProps & React.RefAttributes<SVGSVGElement>
>

interface StatusConfig {
  label: string
  // Badge variant carries the colour; the glyph + label carry the meaning so
  // status never rides on colour alone.
  variant: "success" | "warning" | "destructive" | "secondary"
  glyph: Glyph
}

export const STATUS_CONFIG: Record<EquipmentStatus, StatusConfig> = {
  running: { label: "稼働中", variant: "success", glyph: IconPlayerPlayFilled },
  stopped: { label: "停止", variant: "secondary", glyph: IconPlayerStopFilled },
  fault: { label: "故障", variant: "destructive", glyph: IconAlertTriangleFilled },
  maintenance: { label: "保全中", variant: "warning", glyph: IconTool },
}

/** A status pill that uses an icon + text label, not colour alone. */
export function StatusBadge({ status }: { status: EquipmentStatus }) {
  const cfg = STATUS_CONFIG[status]
  return (
    <Badge variant={cfg.variant} className="gap-1">
      <Icon icon={cfg.glyph} size="xs" />
      {cfg.label}
    </Badge>
  )
}
